class Solution:
    def countNodes(self, root):
        if not root:
            return 0
        lh = self._left_height(root)
        rh = self._right_height(root)
        if lh == rh:
            return (1 << lh) - 1
        return 1 + self.countNodes(root.left) + self.countNodes(root.right)

    def _left_height(self, node):
        h = 0
        while node:
            h += 1
            node = node.left
        return h

    def _right_height(self, node):
        h = 0
        while node:
            h += 1
            node = node.right
        return h

